class Solution {
public:
    int rearrangeCharacters(string s, string target) {
        vector<int> s_count(26, 0);
        vector<int> target_count(26, 0);

        for (char c : s) {
            s_count[c - 'a']++;
        }

        for (char c : target) {
            target_count[c - 'a']++;
        }

        int max_copies = INT_MAX;
        for (int i = 0; i < 26; i++) {
            if (target_count[i] > 0) {
                max_copies = min(max_copies, s_count[i] / target_count[i]);
            }
        }

        return max_copies;
    }
};
